/* CompTIA AI Fundamentals :: content/quiz4.js — question bank for Domain 4 (100 items). */
window.AIFUND = window.AIFUND || {}; AIFUND.questions = AIFUND.questions || [];
AIFUND.questions.push(
{ id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"A chatbot confidently states a court case and citation that do not actually exist. What is this kind of AI error called?", options:["A hallucination","A syntax error","A permissions error","A rate limit"], answer:0, explain:"<strong>A hallucination</strong> is when a generative AI produces information that sounds plausible and confident but is fabricated, such as a made-up court case or citation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A syntax error</b>: a syntax error is a coding mistake in a program, not a false fact stated in fluent language.</span><span class='qd'><b>A permissions error</b>: a permissions error means you lack access to a resource, which is unrelated to invented content.</span><span class='qd'><b>A rate limit</b>: a rate limit restricts how many requests you can send and does not describe fabricated output.</span>" },
{ id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"You ask a free AI assistant about a phone released last week and it says it has no knowledge of it. What is the MOST likely reason?", options:["The phone does not exist","The model's training data has a cutoff date before the release","Your account lacks permission","The model is broken and should be reinstalled"], answer:1, explain:"<strong>The model's training data has a cutoff date before the release</strong> explains why a model without live web access cannot know about very recent events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The phone does not exist</b>: the model's silence reflects its training window, not proof that a real product is fictional.</span><span class='qd'><b>Your account lacks permission</b>: knowledge cutoffs are not a permissions issue tied to your account.</span><span class='qd'><b>The model is broken and should be reinstalled</b>: not knowing recent events is expected behavior, not a defect to reinstall.</span>" },
{ id:"D4-003", domain:4, obj:"4.1", diff:"easy", q:"Which statement BEST describes why AI hallucinations are especially risky?", options:["They always contain obvious spelling mistakes","They only occur when the internet is down","They are written in fluent, confident language that seems trustworthy","They are clearly labeled as guesses by the tool"], answer:2, explain:"<strong>They are written in fluent, confident language that seems trustworthy</strong> is what makes hallucinations dangerous, because the polished tone hides the fact that the content is invented.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They always contain obvious spelling mistakes</b>: hallucinations are usually grammatically clean, which is precisely why they fool people.</span><span class='qd'><b>They only occur when the internet is down</b>: hallucinations stem from how the model generates text, not from connectivity.</span><span class='qd'><b>They are clearly labeled as guesses by the tool</b>: most tools present fabricated content with the same confidence as facts, without a warning label.</span>" },
{ id:"D4-004", domain:4, obj:"4.1", diff:"easy", q:"An AI writing assistant gives you a statistic with no source. Before using it in a report, you should FIRST:", options:["Publish it because the AI sounded certain","Reword it so it sounds more formal","Assume it is correct if it matches your expectations","Verify the statistic against a reliable primary source"], answer:3, explain:"<strong>Verify the statistic against a reliable primary source</strong> is the correct first step, because unsourced AI figures may be fabricated or outdated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it because the AI sounded certain</b>: confidence in tone is not evidence of accuracy.</span><span class='qd'><b>Reword it so it sounds more formal</b>: rewording changes style but does nothing to confirm the number is real.</span><span class='qd'><b>Assume it is correct if it matches your expectations</b>: matching your bias does not make a figure true and can reinforce an error.</span>" },
{ id:"D4-005", domain:4, obj:"4.1", diff:"easy", q:"Which of the following is an example of AI returning outdated information rather than a hallucination?", options:["Naming a company's CEO who left the role after the model's training cutoff","Inventing a research paper that was never written","Fabricating a fake quote attributed to a real person","Making up a statistic with a precise but false number"], answer:0, explain:"<strong>Naming a company's CEO who left the role after the model's training cutoff</strong> is outdated information, because the fact was true when the model learned it but has since changed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inventing a research paper that was never written</b>: a paper that never existed is a fabrication, not a fact that became stale.</span><span class='qd'><b>Fabricating a fake quote attributed to a real person</b>: a made-up quote is a hallucination, not out-of-date knowledge.</span><span class='qd'><b>Making up a statistic with a precise but false number</b>: an invented number is fabricated, not simply outdated.</span>" },
{ id:"D4-006", domain:4, obj:"4.1", diff:"easy", q:"A colleague says \"the AI can't be wrong, it's a computer.\" What is the BEST correction?", options:["Computers are always right, so the colleague is correct","Generative AI predicts likely text and can produce confident but false answers","AI is only wrong when it displays an error message","AI errors happen only with paid tools"], answer:1, explain:"<strong>Generative AI predicts likely text and can produce confident but false answers</strong> correctly explains that these systems generate plausible wording rather than guaranteed facts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Computers are always right, so the colleague is correct</b>: this repeats the misconception; AI can and does produce incorrect output.</span><span class='qd'><b>AI is only wrong when it displays an error message</b>: hallucinations arrive without any error message, looking just like correct answers.</span><span class='qd'><b>AI errors happen only with paid tools</b>: both free and paid tools can hallucinate, so cost is irrelevant.</span>" },
{ id:"D4-007", domain:4, obj:"4.1", diff:"easy", q:"You ask an AI for directions to a local store and it gives a confident but wrong address. What single habit would have caught this fastest?", options:["Asking the AI the same question again in the same chat","Trusting it because it was very specific","Cross-checking the address with a maps service","Rewriting the question in all capital letters"], answer:2, explain:"<strong>Cross-checking the address with a maps service</strong> is the fastest safeguard, because an authoritative external source quickly confirms or corrects the AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking the AI the same question again in the same chat</b>: re-asking may just repeat the same error and offers no independent verification.</span><span class='qd'><b>Trusting it because it was very specific</b>: precise-sounding detail is a common feature of hallucinations, not proof of accuracy.</span><span class='qd'><b>Rewriting the question in all capital letters</b>: capitalization does not change the reliability of the answer.</span>" },
{ id:"D4-008", domain:4, obj:"4.1", diff:"easy", q:"Which situation is MOST likely to trigger an AI hallucination?", options:["Asking a simple, widely documented arithmetic question","Asking it to summarize text you pasted in","Asking for a definition of a common everyday word","Asking about a very niche topic with little public information"], answer:3, explain:"<strong>Asking about a very niche topic with little public information</strong> raises hallucination risk, because with sparse data the model fills gaps by inventing plausible-sounding details.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking a simple, widely documented arithmetic question</b>: common, well-covered facts are far less prone to fabrication.</span><span class='qd'><b>Asking it to summarize text you pasted in</b>: summarizing supplied text keeps the model grounded in your source, reducing invention.</span><span class='qd'><b>Asking for a definition of a common everyday word</b>: everyday definitions are heavily represented in training data and rarely hallucinated.</span>" },
{ id:"D4-009", domain:4, obj:"4.1", diff:"medium", q:"An AI tool provides a URL as a source, but when you click it the page returns \"404 not found.\" What is the MOST likely explanation?", options:["The AI generated a plausible-looking but fabricated link","The website is temporarily blocking your country","Your browser cache needs clearing","The link is real but the AI misspelled the domain on purpose"], answer:0, explain:"<strong>The AI generated a plausible-looking but fabricated link</strong> is most likely, because models can invent URLs that follow a real pattern yet point to nothing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The website is temporarily blocking your country</b>: geo-blocking usually returns an access-denied message, not a 404, and is far less common than a fabricated link.</span><span class='qd'><b>Your browser cache needs clearing</b>: a stale cache would not cause a brand-new invented URL to fail.</span><span class='qd'><b>The link is real but the AI misspelled the domain on purpose</b>: models do not intentionally misspell; the simpler cause is that the link was never real.</span>" },
{ id:"D4-010", domain:4, obj:"4.1", diff:"medium", q:"You paste a long PDF into an AI and ask for the total on page 12, but the number it gives is not in the document. This is BEST described as:", options:["A network timeout","A hallucination grounded in a real document but still incorrect","A file corruption issue","A licensing restriction"], answer:1, explain:"<strong>A hallucination grounded in a real document but still incorrect</strong> fits, because even with a source provided the model can misread or invent a figure that is not actually present.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A network timeout</b>: a timeout would prevent an answer entirely, not produce a specific wrong number.</span><span class='qd'><b>A file corruption issue</b>: corruption would typically cause an upload failure or garbled text, not a confident false total.</span><span class='qd'><b>A licensing restriction</b>: licensing limits access to content and does not explain a fabricated figure.</span>" },
{ id:"D4-011", domain:4, obj:"4.1", diff:"medium", q:"An assistant tells you a law changed \"last year,\" but you know the model's knowledge stops two years ago. What is the safest interpretation?", options:["The model must have live internet access","The law definitely changed exactly as described","The claim about a recent change may be a hallucination and needs verification","Knowledge cutoffs do not affect legal questions"], answer:2, explain:"<strong>The claim about a recent change may be a hallucination and needs verification</strong> is safest, because a model referencing events after its cutoff is likely inventing or guessing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model must have live internet access</b>: many assistants have no live access, so a confident recent claim is not evidence of it.</span><span class='qd'><b>The law definitely changed exactly as described</b>: accepting an unverifiable recent claim risks acting on fabricated detail.</span><span class='qd'><b>Knowledge cutoffs do not affect legal questions</b>: cutoffs affect every topic, including law, where currency matters greatly.</span>" },
{ id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"Which behavior BEST reduces the chance of acting on outdated AI information?", options:["Trusting the AI more if it gives an exact date","Only using AI tools released this month","Assuming any answer with numbers is current","Checking a current authoritative source for anything time-sensitive"], answer:3, explain:"<strong>Checking a current authoritative source for anything time-sensitive</strong> directly addresses staleness by confirming the latest facts from an up-to-date reference.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusting the AI more if it gives an exact date</b>: a precise date can itself be fabricated or outdated and is not a currency guarantee.</span><span class='qd'><b>Only using AI tools released this month</b>: a tool's release date does not determine how recent its training data is.</span><span class='qd'><b>Assuming any answer with numbers is current</b>: numbers can be just as stale or invented as any other content.</span>" },
{ id:"D4-013", domain:4, obj:"4.1", diff:"medium", q:"An AI summarizes a news event but adds a detail no source mentions. When you ask where the detail came from, it apologizes and removes it. What does this illustrate?", options:["Models can fabricate details and cannot reliably cite their own reasoning","The detail was true but secret","The tool intentionally lied to save time","Only the paid version does this"], answer:0, explain:"<strong>Models can fabricate details and cannot reliably cite their own reasoning</strong> is the lesson, because the apology and retraction show the detail had no real source behind it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The detail was true but secret</b>: retracting on request indicates it was unsupported, not a hidden truth.</span><span class='qd'><b>The tool intentionally lied to save time</b>: this was an unsupported generation, not a deliberate lie with intent.</span><span class='qd'><b>Only the paid version does this</b>: fabrication is a general model behavior, not limited to paid tiers.</span>" },
{ id:"D4-014", domain:4, obj:"4.1", diff:"medium", q:"You ask an AI to \"list the five studies that prove this\" and it produces five formatted citations. What is the responsible next step?", options:["Copy them into your paper because they look real","Search for each citation to confirm the studies actually exist","Assume at least three of five must be genuine","Trust them because they include page numbers"], answer:1, explain:"<strong>Search for each citation to confirm the studies actually exist</strong> is responsible, because AI-generated reference lists frequently contain fabricated papers that look authentic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copy them into your paper because they look real</b>: appearance is exactly what fabricated citations imitate, so looks are not proof.</span><span class='qd'><b>Assume at least three of five must be genuine</b>: there is no reliable ratio; any or all of them could be invented.</span><span class='qd'><b>Trust them because they include page numbers</b>: page numbers are easily fabricated and do not verify a source.</span>" },
{ id:"D4-015", domain:4, obj:"4.1", diff:"medium", q:"When asked the same factual question twice, an AI gives two different answers. What is the BEST conclusion?", options:["The most recent answer is always correct","The longer answer is the correct one","At least one answer is unreliable, so both need verification","The tool is malfunctioning and unusable"], answer:2, explain:"<strong>At least one answer is unreliable, so both need verification</strong> follows logically, since contradictory outputs cannot both be right and signal a need to confirm externally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The most recent answer is always correct</b>: recency in a chat does not make an answer accurate.</span><span class='qd'><b>The longer answer is the correct one</b>: length has no bearing on correctness.</span><span class='qd'><b>The tool is malfunctioning and unusable</b>: variability is normal model behavior, not a defect making the tool unusable.</span>" },
{ id:"D4-016", domain:4, obj:"4.1", diff:"medium", q:"Which task is MOST vulnerable to a subtle, hard-to-spot hallucination?", options:["Reversing a short sentence you provided","Counting the words in a phrase you supplied","Translating a common greeting into another language","Producing a detailed financial figure inside an otherwise accurate summary"], answer:3, explain:"<strong>Producing a detailed financial figure inside an otherwise accurate summary</strong> is most vulnerable, because one wrong number buried in correct context is easy to overlook.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reversing a short sentence you provided</b>: a simple mechanical transformation of your own text has little room for invented facts.</span><span class='qd'><b>Counting the words in a phrase you supplied</b>: this is a small, checkable operation on provided input.</span><span class='qd'><b>Translating a common greeting into another language</b>: common greetings are well documented and low risk for fabrication.</span>" },
{ id:"D4-017", domain:4, obj:"4.1", diff:"medium", q:"An AI states a historical date with total confidence, but it conflicts with your textbook. What should you trust and why?", options:["The textbook, because a vetted source outranks a model's confident guess","The AI, because it processed more information","Whichever you saw first","The AI, because textbooks are often wrong"], answer:0, explain:"<strong>The textbook, because a vetted source outranks a model's confident guess</strong> is correct, since editorially reviewed references are more reliable than AI-generated confidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI, because it processed more information</b>: processing volume does not guarantee accuracy on a specific fact.</span><span class='qd'><b>Whichever you saw first</b>: order of exposure is irrelevant to which source is trustworthy.</span><span class='qd'><b>The AI, because textbooks are often wrong</b>: while no source is perfect, a vetted textbook is generally more reliable than an unverified model claim.</span>" },
{ id:"D4-018", domain:4, obj:"4.1", diff:"medium", q:"A model claims a software feature exists in an app, but you cannot find it anywhere. This is an example of:", options:["A hidden feature only experts can access","A hallucinated feature that should be verified in the app's documentation","A bug in the app you should report","A licensing tier you have not purchased"], answer:1, explain:"<strong>A hallucinated feature that should be verified in the app's documentation</strong> fits, because models sometimes describe capabilities a product does not actually have.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hidden feature only experts can access</b>: assuming a secret feature is speculation; the documentation is the authoritative check.</span><span class='qd'><b>A bug in the app you should report</b>: the app is not broken simply because the AI described a nonexistent feature.</span><span class='qd'><b>A licensing tier you have not purchased</b>: without evidence the feature exists at all, blaming a paywall is a guess.</span>" },
{ id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"Why can an AI give a wrong answer to a basic math word problem even though calculators never do?", options:["Calculators and AI use the exact same logic","It runs out of memory on small numbers","It predicts language patterns rather than truly calculating each step","It always rounds every number down"], answer:2, explain:"<strong>It predicts language patterns rather than truly calculating each step</strong> explains the error, because a language model generates likely text and may not perform reliable arithmetic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Calculators and AI use the exact same logic</b>: a calculator executes exact arithmetic, while a language model predicts tokens.</span><span class='qd'><b>It runs out of memory on small numbers</b>: small-number errors are not a memory-capacity problem.</span><span class='qd'><b>It always rounds every number down</b>: there is no such universal rounding rule; errors are inconsistent.</span>" },
{ id:"D4-020", domain:4, obj:"4.1", diff:"medium", q:"You notice an AI answer contradicts itself between paragraph one and paragraph three. What is the MOST appropriate response?", options:["Keep only paragraph one and ignore the rest","Assume the contradiction cancels out to a correct middle","Immediately switch to a different AI brand","Treat the whole answer as suspect and verify the key claims"], answer:3, explain:"<strong>Treat the whole answer as suspect and verify the key claims</strong> is appropriate, because an internal contradiction signals unreliability throughout the response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep only paragraph one and ignore the rest</b>: there is no basis to assume the first paragraph is the correct one.</span><span class='qd'><b>Assume the contradiction cancels out to a correct middle</b>: contradictions do not average into truth.</span><span class='qd'><b>Immediately switch to a different AI brand</b>: switching tools does not verify the facts you actually need.</span>" },
{ id:"D4-021", domain:4, obj:"4.1", diff:"hard", q:"An AI assistant integrated with live web search still cites a source that, when opened, does not contain the claimed quote. What is the MOST accurate takeaway?", options:["Even retrieval-connected tools can misattribute or invent quotes, so quotes must be checked at the source","Web-connected tools never make citation mistakes","The quote is correct because a link was attached","The source website deleted the quote to hide it"], answer:0, explain:"<strong>Even retrieval-connected tools can misattribute or invent quotes, so quotes must be checked at the source</strong> is most accurate, because retrieval reduces but does not eliminate fabrication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Web-connected tools never make citation mistakes</b>: connecting to the web does not guarantee the model quotes it faithfully.</span><span class='qd'><b>The quote is correct because a link was attached</b>: a link's presence does not prove the quote appears there.</span><span class='qd'><b>The source website deleted the quote to hide it</b>: assuming deletion is speculation when the simpler explanation is misattribution.</span>" },
{ id:"D4-022", domain:4, obj:"4.1", diff:"hard", q:"A financial analyst uses AI to draft a market brief. The AI blends a correct 2019 figure with a fabricated 2024 projection presented identically. What makes this especially dangerous?", options:["The fabricated projection will be flagged automatically","Accurate and fabricated content are indistinguishable in tone, so errors ride along unnoticed","Mixing dates always produces a visible error","The correct 2019 figure guarantees the projection is also correct"], answer:1, explain:"<strong>Accurate and fabricated content are indistinguishable in tone, so errors ride along unnoticed</strong> captures the core danger of mixed-quality AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The fabricated projection will be flagged automatically</b>: tools do not automatically flag fabricated figures as such.</span><span class='qd'><b>Mixing dates always produces a visible error</b>: there is no visible cue simply because two eras are combined.</span><span class='qd'><b>The correct 2019 figure guarantees the projection is also correct</b>: one accurate value says nothing about the truth of another.</span>" },
{ id:"D4-023", domain:4, obj:"4.1", diff:"hard", q:"An AI states \"as of my last update\" and then gives a market share number. For a decision due today, the BEST practice is to:", options:["Use the number as-is since the AI acknowledged its cutoff","Add ten percent to account for growth since the cutoff","Confirm the figure against a current industry report before relying on it","Reject all AI output and abandon the analysis"], answer:2, explain:"<strong>Confirm the figure against a current industry report before relying on it</strong> is best, because an acknowledged cutoff still means the figure may be stale for a same-day decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use the number as-is since the AI acknowledged its cutoff</b>: acknowledging staleness does not make the number current or reliable.</span><span class='qd'><b>Add ten percent to account for growth since the cutoff</b>: inventing an adjustment factor is a guess that can compound the error.</span><span class='qd'><b>Reject all AI output and abandon the analysis</b>: the draft can still be useful once its facts are verified, so abandoning it is an overreaction.</span>" },
{ id:"D4-024", domain:4, obj:"4.1", diff:"hard", q:"Which scenario BEST demonstrates that a confident tone is unrelated to factual accuracy in AI output?", options:["The model uses hedging language like 'I think' before every fact","The model refuses to answer any factual question","The model only sounds confident when it is correct","The model states an invented statute number in the same assured voice it uses for real ones"], answer:3, explain:"<strong>The model states an invented statute number in the same assured voice it uses for real ones</strong> proves tone and truth are decoupled, since fabrication is delivered with equal confidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model uses hedging language like 'I think' before every fact</b>: uniform hedging does not demonstrate the confidence-accuracy gap being illustrated.</span><span class='qd'><b>The model refuses to answer any factual question</b>: refusing to answer shows no relationship between tone and accuracy.</span><span class='qd'><b>The model only sounds confident when it is correct</b>: this is false; models sound equally confident when wrong.</span>" },
{ id:"D4-025", domain:4, obj:"4.1", diff:"hard", q:"A researcher finds an AI-generated literature review is 90 percent accurate. Why is that not good enough to publish without checking?", options:["The 10 percent of errors are invisible without verification and can undermine credibility","90 percent accuracy means the errors are harmless","Reviewers only check for grammar, not facts","Accuracy percentages do not apply to writing"], answer:0, explain:"<strong>The 10 percent of errors are invisible without verification and can undermine credibility</strong> is why partial accuracy is insufficient, since undetected mistakes can invalidate the work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>90 percent accuracy means the errors are harmless</b>: even a small fraction of false claims can be seriously damaging.</span><span class='qd'><b>Reviewers only check for grammar, not facts</b>: reviewers do scrutinize factual claims, so errors will surface.</span><span class='qd'><b>Accuracy percentages do not apply to writing</b>: factual accuracy absolutely applies to written research.</span>" },
{ id:"D4-026", domain:4, obj:"4.1", diff:"hard", q:"An AI tool provides a plausible medical dosage. For a health decision, the MOST responsible action is to:", options:["Follow it if it matches something you read online once","Treat it as unverified and consult a qualified professional or official reference","Trust it because health data is well represented in training","Average it with a dosage from another chatbot"], answer:1, explain:"<strong>Treat it as unverified and consult a qualified professional or official reference</strong> is most responsible, because AI dosage claims can be wrong and carry real-world harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Follow it if it matches something you read online once</b>: a vague memory is not a reliable confirmation for a health decision.</span><span class='qd'><b>Trust it because health data is well represented in training</b>: broad representation does not guarantee correctness for a specific case.</span><span class='qd'><b>Average it with a dosage from another chatbot</b>: averaging two unverified outputs does not produce a safe or valid figure.</span>" },
{ id:"D4-027", domain:4, obj:"4.1", diff:"hard", q:"You give an AI a source document and it summarizes accurately, but adds one sentence with an outside 'fact' not in the document. This mixing is risky mainly because:", options:["The outside fact is always false","Summaries can never include outside information","Readers assume everything in the summary came from the trusted source","The document becomes corrupted"], answer:2, explain:"<strong>Readers assume everything in the summary came from the trusted source</strong> is the key risk, because injected outside content inherits the source's perceived authority.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The outside fact is always false</b>: it may or may not be true, but the danger is that its origin is misattributed.</span><span class='qd'><b>Summaries can never include outside information</b>: they can, which is exactly the problem being described.</span><span class='qd'><b>The document becomes corrupted</b>: the source file is unchanged; the issue is the added claim in the summary.</span>" },
{ id:"D4-028", domain:4, obj:"4.1", diff:"hard", q:"An AI confidently describes the outcome of an event that occurred after its stated knowledge cutoff. The BEST explanation is that it:", options:["Secretly accessed future data","Was updated in real time without notice","Correctly predicted the outcome and can be trusted","Generated a plausible guess it cannot actually know to be true"], answer:3, explain:"<strong>Generated a plausible guess it cannot actually know to be true</strong> is correct, because a model cannot have factual knowledge of events past its cutoff.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Secretly accessed future data</b>: models cannot access information from beyond their training window without a live connection.</span><span class='qd'><b>Was updated in real time without notice</b>: a static model is not silently retrained mid-conversation.</span><span class='qd'><b>Correctly predicted the outcome and can be trusted</b>: a confident guess about a post-cutoff event is not trustworthy without verification.</span>" },
{ id:"D4-029", domain:4, obj:"4.1", diff:"medium", q:"Which of these is the clearest sign an AI answer may contain a hallucination?", options:["It cites specific sources you cannot locate anywhere","It uses simple, common vocabulary","It restates a fact from your own pasted text","It says 'I am not certain' before answering"], answer:0, explain:"<strong>It cites specific sources you cannot locate anywhere</strong> is a strong warning sign, because unfindable references are a classic fabrication pattern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It uses simple, common vocabulary</b>: plain wording says nothing about factual accuracy.</span><span class='qd'><b>It restates a fact from your own pasted text</b>: echoing your supplied content is grounded, not hallucinated.</span><span class='qd'><b>It says 'I am not certain' before answering</b>: an explicit hedge is actually a helpful signal, not evidence of fabrication.</span>" },
{ id:"D4-030", domain:4, obj:"4.1", diff:"medium", q:"An AI gives you code that references a library function that does not exist. This is BEST described as:", options:["A version conflict you cannot fix","A hallucinated function name that should be checked in the official docs","Proof the programming language is broken","A sign the AI needs more RAM"], answer:1, explain:"<strong>A hallucinated function name that should be checked in the official docs</strong> fits, because models can invent API calls that look real but are not part of the library.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A version conflict you cannot fix</b>: a nonexistent function is not merely a version mismatch of a real one.</span><span class='qd'><b>Proof the programming language is broken</b>: the language works fine; the invented call is the issue.</span><span class='qd'><b>A sign the AI needs more RAM</b>: fabrication is unrelated to the tool's memory resources.</span>" },
{ id:"D4-031", domain:4, obj:"4.2", diff:"easy", q:"Which phrase BEST describes low-effort, generic, mass-produced AI text with little real value?", options:["Prompt injection","Fine-tuning","AI slop","Tokenization"], answer:2, explain:"<strong>AI slop</strong> is the common term for bland, repetitive, low-quality AI-generated content produced in bulk with little substance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prompt injection</b>: prompt injection is an attack that manipulates an AI's instructions, not a description of low-value content.</span><span class='qd'><b>Fine-tuning</b>: fine-tuning is a training technique to adapt a model, unrelated to describing poor output.</span><span class='qd'><b>Tokenization</b>: tokenization is how text is broken into units for processing, not a quality label.</span>" },
{ id:"D4-032", domain:4, obj:"4.2", diff:"easy", q:"An AI hiring tool consistently ranks male applicants higher for the same qualifications. This is an example of:", options:["A hardware failure","A spelling error","A network latency issue","Bias in the AI's output"], answer:3, explain:"<strong>Bias in the AI's output</strong> describes systematic unfairness, such as favoring one group over another with equal qualifications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hardware failure</b>: unfair ranking is a data and model issue, not a physical component breaking.</span><span class='qd'><b>A spelling error</b>: a spelling mistake has nothing to do with skewed rankings.</span><span class='qd'><b>A network latency issue</b>: latency affects speed, not the fairness of results.</span>" },
{ id:"D4-033", domain:4, obj:"4.2", diff:"easy", q:"Where does bias in an AI system most commonly originate?", options:["Patterns in the data it was trained on","The color of the user interface","The user's typing speed","The brand of the computer running it"], answer:0, explain:"<strong>Patterns in the data it was trained on</strong> is the primary source of bias, since a model reflects the skews and gaps present in its training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color of the user interface</b>: visual design does not shape the fairness of model predictions.</span><span class='qd'><b>The user's typing speed</b>: how fast someone types has no effect on learned bias.</span><span class='qd'><b>The brand of the computer running it</b>: the hardware brand does not influence biased outputs.</span>" },
{ id:"D4-034", domain:4, obj:"4.2", diff:"easy", q:"Which of the following is a hallmark of \"AI slop\" content?", options:["Precise, well-sourced original analysis","Vague, repetitive filler that says little of substance","A carefully verified data table","A concise answer tailored to your exact question"], answer:1, explain:"<strong>Vague, repetitive filler that says little of substance</strong> is a hallmark of slop, which pads length without delivering real information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Precise, well-sourced original analysis</b>: strong sourcing and originality are the opposite of slop.</span><span class='qd'><b>A carefully verified data table</b>: verified data reflects quality, not low-effort filler.</span><span class='qd'><b>A concise answer tailored to your exact question</b>: relevance and concision are signs of useful output, not slop.</span>" },
{ id:"D4-035", domain:4, obj:"4.2", diff:"easy", q:"You read an online article that repeats the same generic sentence in different words several times and cites nothing. This is a warning sign of:", options:["A peer-reviewed study","A primary source document","Low-quality, possibly AI-generated slop","An official government record"], answer:2, explain:"<strong>Low-quality, possibly AI-generated slop</strong> is signaled by repetitive, source-free padding that adds no new information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A peer-reviewed study</b>: peer-reviewed work is structured, cited, and substantive, unlike padded filler.</span><span class='qd'><b>A primary source document</b>: a primary source presents original evidence, not recycled generic sentences.</span><span class='qd'><b>An official government record</b>: official records contain specific, verifiable detail rather than empty repetition.</span>" },
{ id:"D4-036", domain:4, obj:"4.2", diff:"easy", q:"Why is representative, diverse training data important for reducing AI bias?", options:["It makes the model run faster","It reduces the file size of the model","It changes the interface language automatically","It helps the model reflect a wider range of people and situations fairly"], answer:3, explain:"<strong>It helps the model reflect a wider range of people and situations fairly</strong>, because diverse data reduces blind spots that lead to skewed outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the model run faster</b>: data diversity affects fairness, not processing speed.</span><span class='qd'><b>It reduces the file size of the model</b>: representativeness does not shrink the model.</span><span class='qd'><b>It changes the interface language automatically</b>: training data variety does not switch the UI language.</span>" },
{ id:"D4-037", domain:4, obj:"4.2", diff:"easy", q:"An image generator asked for \"a nurse\" only ever produces women. This pattern MOST likely reflects:", options:["Bias learned from imbalanced training images","A rendering glitch in the graphics card","A copyright restriction","A slow internet connection"], answer:0, explain:"<strong>Bias learned from imbalanced training images</strong> explains the pattern, because the model reproduces the demographic skew of its training set.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A rendering glitch in the graphics card</b>: a hardware glitch would distort images, not consistently choose one gender.</span><span class='qd'><b>A copyright restriction</b>: copyright limits what content is used, not the demographic patterns in outputs.</span><span class='qd'><b>A slow internet connection</b>: connection speed has no bearing on who appears in generated images.</span>" },
{ id:"D4-038", domain:4, obj:"4.2", diff:"easy", q:"Which action BEST helps you notice bias in an AI's answer about a group of people?", options:["Check whether the font is easy to read","Ask whether the answer relies on stereotypes or overgeneralizations","Count how many sentences it contains","See if it responds quickly"], answer:1, explain:"<strong>Ask whether the answer relies on stereotypes or overgeneralizations</strong> helps surface bias by prompting scrutiny of unfair assumptions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Check whether the font is easy to read</b>: readability is unrelated to biased content.</span><span class='qd'><b>Count how many sentences it contains</b>: length does not reveal whether the reasoning is fair.</span><span class='qd'><b>See if it responds quickly</b>: speed says nothing about bias.</span>" },
{ id:"D4-039", domain:4, obj:"4.2", diff:"medium", q:"A marketing team floods a blog with dozens of near-identical AI articles to game search rankings. This practice BEST illustrates:", options:["A responsible content strategy","A cybersecurity control","Producing AI slop that harms content quality and reader trust","A data backup procedure"], answer:2, explain:"<strong>Producing AI slop that harms content quality and reader trust</strong> describes churning out low-value, repetitive pages purely for volume.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A responsible content strategy</b>: mass-producing near-identical filler is the opposite of responsible content.</span><span class='qd'><b>A cybersecurity control</b>: this has nothing to do with protecting systems or data.</span><span class='qd'><b>A data backup procedure</b>: publishing bulk articles is unrelated to backing up data.</span>" },
{ id:"D4-040", domain:4, obj:"4.2", diff:"medium", q:"An AI summarizer of customer reviews consistently downplays complaints from older customers. What should you suspect?", options:["The reviews were written incorrectly","The summarizer needs a faster processor","The complaints were not important anyway","The model may carry bias that skews how certain groups are represented"], answer:3, explain:"<strong>The model may carry bias that skews how certain groups are represented</strong> is the right suspicion when one group's input is systematically minimized.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The reviews were written incorrectly</b>: blaming the customers ignores the systematic skew in the summary.</span><span class='qd'><b>The summarizer needs a faster processor</b>: speed does not cause selective downplaying of content.</span><span class='qd'><b>The complaints were not important anyway</b>: dismissing the complaints accepts the very bias you should question.</span>" },
{ id:"D4-041", domain:4, obj:"4.2", diff:"medium", q:"Which of the following BEST distinguishes AI slop from a genuine hallucination?", options:["Slop is low-value but may be true, while a hallucination is a confident false claim","They are exactly the same thing","Slop always contains fabricated citations","Hallucinations are always long and repetitive"], answer:0, explain:"<strong>Slop is low-value but may be true, while a hallucination is a confident false claim</strong> captures the distinction between empty quality and factual falsehood.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are exactly the same thing</b>: they are different problems, one about value and one about truth.</span><span class='qd'><b>Slop always contains fabricated citations</b>: slop can be accurate yet worthless, so fabrication is not required.</span><span class='qd'><b>Hallucinations are always long and repetitive</b>: hallucinations can be short and specific, not necessarily lengthy.</span>" },
{ id:"D4-042", domain:4, obj:"4.2", diff:"medium", q:"An AI translation tool renders professional titles as male by default and family roles as female by default. This is an example of:", options:["A font compatibility problem","Gender bias reflected in language outputs","An encryption error","A slow response time"], answer:1, explain:"<strong>Gender bias reflected in language outputs</strong> describes defaulting to gendered assumptions in translation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A font compatibility problem</b>: fonts do not assign gender to words.</span><span class='qd'><b>An encryption error</b>: encryption is unrelated to translation choices.</span><span class='qd'><b>A slow response time</b>: latency does not cause gendered defaults.</span>" },
{ id:"D4-043", domain:4, obj:"4.2", diff:"medium", q:"You are reviewing AI-generated content and notice it uses many words but never answers the actual question. The BEST label is:", options:["A well-scoped, relevant answer","A verified factual summary","Slop that pads length without addressing the request","A concise expert response"], answer:2, explain:"<strong>Slop that pads length without addressing the request</strong> is the right label for verbose output that avoids the point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A well-scoped, relevant answer</b>: relevance is exactly what this content lacks.</span><span class='qd'><b>A verified factual summary</b>: padding is not the same as a verified summary.</span><span class='qd'><b>A concise expert response</b>: the content is neither concise nor on-target.</span>" },
{ id:"D4-044", domain:4, obj:"4.2", diff:"medium", q:"An AI loan-screening model was trained mostly on data from one region. Why might its decisions be unfair elsewhere?", options:["It will simply run slower in other regions","It will change currency automatically","It cannot process text from other regions","It may not represent other regions' populations, producing skewed outcomes"], answer:3, explain:"<strong>It may not represent other regions' populations, producing skewed outcomes</strong> explains how narrow training data leads to unfair results for underrepresented groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It will simply run slower in other regions</b>: fairness, not speed, is the concern with unrepresentative data.</span><span class='qd'><b>It will change currency automatically</b>: currency conversion is irrelevant to biased decisions.</span><span class='qd'><b>It cannot process text from other regions</b>: the model can process the text; the issue is skewed judgments.</span>" },
{ id:"D4-045", domain:4, obj:"4.2", diff:"medium", q:"Which practice BEST helps a reviewer catch biased AI output before publishing?", options:["Testing the same prompt across different groups or perspectives and comparing results","Publishing quickly to save time","Only reading the first sentence","Trusting the output if it is grammatically clean"], answer:0, explain:"<strong>Testing the same prompt across different groups or perspectives and comparing results</strong> exposes inconsistencies that reveal bias.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publishing quickly to save time</b>: rushing skips the review that would catch bias.</span><span class='qd'><b>Only reading the first sentence</b>: a partial read misses biased content later in the output.</span><span class='qd'><b>Trusting the output if it is grammatically clean</b>: clean grammar has no bearing on fairness.</span>" },
{ id:"D4-046", domain:4, obj:"4.2", diff:"medium", q:"A news aggregator's AI keeps recommending only one political viewpoint to a user. This pattern is BEST described as:", options:["A random error with no cause","Bias that can create a narrow, one-sided information experience","A helpful personalization with no downsides","A hardware overheating problem"], answer:1, explain:"<strong>Bias that can create a narrow, one-sided information experience</strong> describes skewed recommendations that limit exposure to other views.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random error with no cause</b>: the pattern is systematic, not random, and reflects underlying bias.</span><span class='qd'><b>A helpful personalization with no downsides</b>: one-sided feeds carry real downsides for balanced understanding.</span><span class='qd'><b>A hardware overheating problem</b>: overheating does not shape recommendation content.</span>" },
{ id:"D4-047", domain:4, obj:"4.2", diff:"medium", q:"Why might purely AI-written content flood the internet with slop over time?", options:["It is expensive and slow to produce","It always requires expert human review first","It is cheap and fast to generate at scale with little quality control","Search engines block all AI content automatically"], answer:2, explain:"<strong>It is cheap and fast to generate at scale with little quality control</strong> explains the flood, because low cost and high speed encourage mass production regardless of value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is expensive and slow to produce</b>: the opposite is true, which is precisely why slop proliferates.</span><span class='qd'><b>It always requires expert human review first</b>: much slop is published with no meaningful review.</span><span class='qd'><b>Search engines block all AI content automatically</b>: search engines do not automatically block all AI content.</span>" },
{ id:"D4-048", domain:4, obj:"4.2", diff:"hard", q:"An AI resume screener favors candidates from certain universities because past hires came from there. What type of bias is this MOST clearly an example of?", options:["A random sampling fluke","A user interface flaw","A network configuration error","Historical bias baked into the training data"], answer:3, explain:"<strong>Historical bias baked into the training data</strong> occurs when a model learns and perpetuates past patterns, such as favoring schools of previous hires.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random sampling fluke</b>: the preference is systematic and rooted in historical data, not chance.</span><span class='qd'><b>A user interface flaw</b>: the screening logic, not the UI, drives the biased outcome.</span><span class='qd'><b>A network configuration error</b>: networking has nothing to do with learned hiring bias.</span>" },
{ id:"D4-049", domain:4, obj:"4.2", diff:"hard", q:"A company wants to reduce bias in an AI tool it uses. Which approach is MOST effective and appropriate for a non-technical team?", options:["Establish human review of outputs and test for unfair patterns across groups","Assume the vendor eliminated all bias already","Increase the model's response length","Change the app's theme to dark mode"], answer:0, explain:"<strong>Establish human review of outputs and test for unfair patterns across groups</strong> is the most practical non-technical safeguard against biased results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the vendor eliminated all bias already</b>: vendors rarely remove all bias, so blind trust leaves risk unaddressed.</span><span class='qd'><b>Increase the model's response length</b>: longer answers do not make outputs fairer.</span><span class='qd'><b>Change the app's theme to dark mode</b>: appearance settings have no effect on bias.</span>" },
{ id:"D4-050", domain:4, obj:"4.2", diff:"hard", q:"An editor notices AI-drafted product descriptions are fluent but interchangeable across very different products. The core quality problem is that the content is:", options:["Too technical for general readers","Generic slop lacking the specific, distinguishing details buyers need","Overly cited with academic references","Written in the wrong language"], answer:1, explain:"<strong>Generic slop lacking the specific, distinguishing details buyers need</strong> identifies the failure, because interchangeable copy conveys no real product information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Too technical for general readers</b>: the issue is emptiness, not excessive technicality.</span><span class='qd'><b>Overly cited with academic references</b>: interchangeable marketing copy is under-informative, not over-cited.</span><span class='qd'><b>Written in the wrong language</b>: the descriptions are fluent, so language is not the problem.</span>" },
{ id:"D4-051", domain:4, obj:"4.2", diff:"hard", q:"Which situation BEST shows that fixing AI bias is not just a technical task but also an organizational responsibility?", options:["A model runs on faster hardware","A tool has a modern interface","A biased output persists because no one defined who reviews and corrects results","A dataset is stored in the cloud"], answer:2, explain:"<strong>A biased output persists because no one defined who reviews and corrects results</strong> shows that governance and accountability, not just code, are needed to address bias.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A model runs on faster hardware</b>: speed is unrelated to who is responsible for fairness.</span><span class='qd'><b>A tool has a modern interface</b>: interface design does not assign review responsibility.</span><span class='qd'><b>A dataset is stored in the cloud</b>: storage location does not determine bias oversight.</span>" },
{ id:"D4-052", domain:4, obj:"4.2", diff:"hard", q:"A teacher suspects student essays are AI slop. Which combination of signs would MOST support that suspicion?", options:["Strong original arguments citing the assigned readings","Personal anecdotes tied to class discussions","Precise references to page numbers in the textbook","Generic claims, repetitive phrasing, and no specific evidence from assigned readings"], answer:3, explain:"<strong>Generic claims, repetitive phrasing, and no specific evidence from assigned readings</strong> together are strong indicators of low-effort, generic AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Strong original arguments citing the assigned readings</b>: originality and specific citations point toward genuine, engaged work.</span><span class='qd'><b>Personal anecdotes tied to class discussions</b>: individual, context-specific detail is a sign of authentic writing.</span><span class='qd'><b>Precise references to page numbers in the textbook</b>: exact, checkable references suggest real engagement with the material.</span>" },
{ id:"D4-053", domain:4, obj:"4.2", diff:"hard", q:"An AI chatbot gives noticeably less helpful medical guidance when a user's message includes a non-English name. This is MOST concerning because it suggests:", options:["The model treats users differently based on identity signals, a fairness problem","The user typed too slowly","The server was overloaded","The chatbot ran out of tokens"], answer:0, explain:"<strong>The model treats users differently based on identity signals, a fairness problem</strong> is the concern, because response quality should not depend on a user's perceived identity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The user typed too slowly</b>: typing speed does not change the substance of an answer.</span><span class='qd'><b>The server was overloaded</b>: server load would slow responses, not selectively lower quality by name.</span><span class='qd'><b>The chatbot ran out of tokens</b>: token limits truncate length; they do not target specific identities.</span>" },
{ id:"D4-054", domain:4, obj:"4.2", diff:"medium", q:"Which of the following is the BEST example of high-quality, non-slop AI-assisted content?", options:["A bulk-generated post copied straight to the web","A draft the author fact-checked, added original insight to, and tailored to the audience","A page repeating one idea in ten slightly different ways","An answer that ignores the specific question asked"], answer:1, explain:"<strong>A draft the author fact-checked, added original insight to, and tailored to the audience</strong> is high quality because a human refined it for accuracy and relevance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A bulk-generated post copied straight to the web</b>: unreviewed bulk output is the definition of slop.</span><span class='qd'><b>A page repeating one idea in ten slightly different ways</b>: repetitive padding adds no value.</span><span class='qd'><b>An answer that ignores the specific question asked</b>: irrelevance is a core trait of slop.</span>" },
{ id:"D4-055", domain:4, obj:"4.2", diff:"medium", q:"A dataset used to train a customer-service AI contains mostly angry complaints. How might this bias the model's tone?", options:["It will respond faster to all users","It will only reply in formal legal language","It may respond in an unexpectedly negative or defensive tone","It will refuse to answer any questions"], answer:2, explain:"<strong>It may respond in an unexpectedly negative or defensive tone</strong> because a model mirrors the emotional patterns dominant in its training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It will respond faster to all users</b>: data tone does not affect response speed.</span><span class='qd'><b>It will only reply in formal legal language</b>: angry complaints would not push the model toward legal phrasing.</span><span class='qd'><b>It will refuse to answer any questions</b>: skewed tone data biases style, it does not cause blanket refusals.</span>" },
{ id:"D4-056", domain:4, obj:"4.3", diff:"easy", q:"When you evaluate whether an AI output is \"fit for purpose,\" you are mainly asking:", options:["Is it the longest possible answer","Does it use advanced vocabulary","Was it generated quickly","Does it actually meet the needs of the specific task and audience"], answer:3, explain:"<strong>Does it actually meet the needs of the specific task and audience</strong> is the essence of fitness for purpose, focusing on usefulness for the real goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Is it the longest possible answer</b>: length does not determine whether output suits the task.</span><span class='qd'><b>Does it use advanced vocabulary</b>: fancy words do not equal fitness for a purpose.</span><span class='qd'><b>Was it generated quickly</b>: speed is unrelated to whether the result meets the need.</span>" },
{ id:"D4-057", domain:4, obj:"4.3", diff:"easy", q:"Which question BEST assesses the ACCURACY of an AI response?", options:["Are the facts and figures correct and verifiable?","Is the paragraph nicely formatted?","Does it sound confident?","Is it written in a friendly tone?"], answer:0, explain:"<strong>Are the facts and figures correct and verifiable?</strong> targets accuracy by checking whether the content is true and can be confirmed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Is the paragraph nicely formatted?</b>: formatting concerns presentation, not factual correctness.</span><span class='qd'><b>Does it sound confident?</b>: confidence is a tone, not a measure of accuracy.</span><span class='qd'><b>Is it written in a friendly tone?</b>: friendliness does not indicate whether facts are right.</span>" },
{ id:"D4-058", domain:4, obj:"4.3", diff:"easy", q:"An AI gives a technically correct answer, but it is far too detailed and technical for a beginner audience. Which quality dimension does it FAIL?", options:["Grammatical correctness","Fitness for the intended audience","Response speed","Spelling accuracy"], answer:1, explain:"<strong>Fitness for the intended audience</strong> is the failed dimension, because correct content still misses if it does not match who will read it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grammatical correctness</b>: the answer can be grammatically fine yet still unsuitable for beginners.</span><span class='qd'><b>Response speed</b>: how fast it appeared is irrelevant to audience fit.</span><span class='qd'><b>Spelling accuracy</b>: spelling is not the problem when the issue is complexity level.</span>" },
{ id:"D4-059", domain:4, obj:"4.3", diff:"easy", q:"Which of the following is the BEST first check on an AI-generated summary of a document you provided?", options:["Is the summary printed in color?","Did the AI respond within two seconds?","Does the summary faithfully reflect what the document actually says?","Does the summary use bullet points?"], answer:2, explain:"<strong>Does the summary faithfully reflect what the document actually says?</strong> is the key check, since a summary must stay true to its source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Is the summary printed in color?</b>: color has nothing to do with faithfulness.</span><span class='qd'><b>Did the AI respond within two seconds?</b>: speed does not indicate accuracy.</span><span class='qd'><b>Does the summary use bullet points?</b>: formatting style is not a measure of correctness.</span>" },
{ id:"D4-060", domain:4, obj:"4.3", diff:"easy", q:"Which output would BEST be judged \"high quality\" for a customer email reply?", options:["Long and full of unrelated background","Correct facts but rude wording","Friendly tone but wrong account details","Accurate, clear, correctly addresses the customer's issue, and matches a professional tone"], answer:3, explain:"<strong>Accurate, clear, correctly addresses the customer's issue, and matches a professional tone</strong> combines all the qualities a good reply needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Long and full of unrelated background</b>: irrelevant padding lowers quality rather than raising it.</span><span class='qd'><b>Correct facts but rude wording</b>: a rude tone undermines a customer reply even when facts are right.</span><span class='qd'><b>Friendly tone but wrong account details</b>: incorrect details defeat the purpose despite a pleasant tone.</span>" },
{ id:"D4-061", domain:4, obj:"4.3", diff:"easy", q:"You ask an AI for a recipe and it lists ingredients but skips the steps. This output primarily lacks:", options:["Completeness for the task","Correct spelling","A friendly tone","Fast delivery"], answer:0, explain:"<strong>Completeness for the task</strong> is missing, because a usable recipe needs both ingredients and the method.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Correct spelling</b>: spelling is not the gap when whole steps are absent.</span><span class='qd'><b>A friendly tone</b>: tone is unrelated to the missing instructions.</span><span class='qd'><b>Fast delivery</b>: speed does not fix an incomplete answer.</span>" },
{ id:"D4-062", domain:4, obj:"4.3", diff:"medium", q:"A manager receives two AI drafts. Draft A is accurate but ignores the required format; Draft B follows the format but has a factual error. Which is closer to fit-for-purpose, and why?", options:["Draft A, because format never matters","Neither is fully fit; both need correction before use","Draft B, because facts never matter","Both are perfect as delivered"], answer:1, explain:"<strong>Neither is fully fit; both need correction before use</strong> is correct, because fitness requires meeting both accuracy and format requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Draft A, because format never matters</b>: format can be a genuine requirement, so ignoring it is a real flaw.</span><span class='qd'><b>Draft B, because facts never matter</b>: a factual error is a serious defect that must be fixed.</span><span class='qd'><b>Both are perfect as delivered</b>: each draft has a distinct shortfall, so neither is ready as-is.</span>" },
{ id:"D4-063", domain:4, obj:"4.3", diff:"medium", q:"Which criterion is MOST important when judging an AI answer that will guide a safety decision?", options:["Creativity of the wording","Length of the response","Accuracy, verified against authoritative sources","Speed of generation"], answer:2, explain:"<strong>Accuracy, verified against authoritative sources</strong> is paramount for safety, where a wrong answer can cause harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Creativity of the wording</b>: creativity is undesirable when correctness is critical.</span><span class='qd'><b>Length of the response</b>: length does not make a safety answer reliable.</span><span class='qd'><b>Speed of generation</b>: a fast but wrong safety answer is dangerous.</span>" },
{ id:"D4-064", domain:4, obj:"4.3", diff:"medium", q:"An AI produces a well-written essay, but half its supporting facts cannot be verified. How should you rate its overall quality?", options:["High, because the writing style is polished","High, because it is grammatically flawless","Low only if the grammar is also poor","Low, because unverifiable facts undermine the whole piece"], answer:3, explain:"<strong>Low, because unverifiable facts undermine the whole piece</strong> is correct, since polished style cannot rescue unreliable substance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High, because the writing style is polished</b>: style does not compensate for unverifiable claims.</span><span class='qd'><b>High, because it is grammatically flawless</b>: grammar is irrelevant to factual reliability.</span><span class='qd'><b>Low only if the grammar is also poor</b>: quality is already low from the facts alone, regardless of grammar.</span>" },
{ id:"D4-065", domain:4, obj:"4.3", diff:"medium", q:"You need a one-paragraph summary but the AI returns three pages. Beyond trimming, what does this reveal about evaluating output?", options:["You must judge output against your actual requirements, not just its correctness","Longer answers are always better","The AI cannot summarize at all","Requirements do not matter if the content is accurate"], answer:0, explain:"<strong>You must judge output against your actual requirements, not just its correctness</strong> is the lesson, because meeting the brief matters as much as being right.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Longer answers are always better</b>: exceeding a length requirement is a failure, not a bonus.</span><span class='qd'><b>The AI cannot summarize at all</b>: it can summarize; it simply ignored the length constraint here.</span><span class='qd'><b>Requirements do not matter if the content is accurate</b>: accurate content that misses the brief is still unfit.</span>" },
{ id:"D4-066", domain:4, obj:"4.3", diff:"medium", q:"An AI answer is accurate and complete but written at a graduate reading level for a public flyer. The BEST fix is to:", options:["Publish it unchanged because the facts are right","Ask the AI to rewrite it at a simpler reading level for the audience","Make it even more technical","Delete the flyer project entirely"], answer:1, explain:"<strong>Ask the AI to rewrite it at a simpler reading level for the audience</strong> restores fitness by matching the content to the readers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it unchanged because the facts are right</b>: correct facts do not help if the audience cannot follow the writing.</span><span class='qd'><b>Make it even more technical</b>: adding complexity worsens the mismatch.</span><span class='qd'><b>Delete the flyer project entirely</b>: abandoning the task is unnecessary when a simple rewrite fixes it.</span>" },
{ id:"D4-067", domain:4, obj:"4.3", diff:"medium", q:"Which set of criteria BEST represents a well-rounded evaluation of AI output?", options:["Only how confident the tone is","Only how fast it was produced","Accuracy, relevance, completeness, and fitness for the audience","Only how long the response is"], answer:2, explain:"<strong>Accuracy, relevance, completeness, and fitness for the audience</strong> covers the main dimensions of a thorough evaluation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only how confident the tone is</b>: tone alone ignores whether the content is correct or useful.</span><span class='qd'><b>Only how fast it was produced</b>: speed is one minor factor, not a full evaluation.</span><span class='qd'><b>Only how long the response is</b>: length says nothing about quality.</span>" },
{ id:"D4-068", domain:4, obj:"4.3", diff:"medium", q:"A translated document from an AI reads smoothly but changes the meaning of a key legal clause. Which quality issue is MOST serious here?", options:["Formatting, because the spacing looks off","Speed, because it took a moment","Tone, because it sounds formal","Accuracy, because the altered meaning could have legal consequences"], answer:3, explain:"<strong>Accuracy, because the altered meaning could have legal consequences</strong> is the gravest issue in a legal translation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Formatting, because the spacing looks off</b>: spacing is trivial next to a changed legal meaning.</span><span class='qd'><b>Speed, because it took a moment</b>: response time is irrelevant to a meaning error.</span><span class='qd'><b>Tone, because it sounds formal</b>: formality does not offset a substantive mistranslation.</span>" },
{ id:"D4-069", domain:4, obj:"4.3", diff:"hard", q:"An AI produces a report that is accurate but omits a critical caveat the audience needs to act safely. In evaluation terms, the output is:", options:["Incomplete in a way that reduces its fitness despite being accurate","Fully fit because every stated fact is true","Low quality only because of its formatting","Perfectly acceptable since caveats are optional"], answer:0, explain:"<strong>Incomplete in a way that reduces its fitness despite being accurate</strong> is correct, because a missing critical caveat can make accurate content unsafe to use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fully fit because every stated fact is true</b>: fitness requires completeness, not just true statements.</span><span class='qd'><b>Low quality only because of its formatting</b>: the problem is a missing caveat, not formatting.</span><span class='qd'><b>Perfectly acceptable since caveats are optional</b>: a critical caveat is not optional when safety depends on it.</span>" },
{ id:"D4-070", domain:4, obj:"4.3", diff:"hard", q:"Two AI answers are equally accurate. Answer 1 directly solves the user's stated problem; Answer 2 solves a related but different problem. Which is higher quality and why?", options:["Answer 2, because it covers more ground","Answer 1, because relevance to the actual need is a core quality dimension","They are identical since both are accurate","Answer 2, because different is more creative"], answer:1, explain:"<strong>Answer 1, because relevance to the actual need is a core quality dimension</strong> is correct, since accuracy without relevance still fails the user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Answer 2, because it covers more ground</b>: covering the wrong problem is not an advantage.</span><span class='qd'><b>They are identical since both are accurate</b>: relevance differentiates them despite equal accuracy.</span><span class='qd'><b>Answer 2, because different is more creative</b>: creativity that misses the need lowers usefulness.</span>" },
{ id:"D4-071", domain:4, obj:"4.3", diff:"hard", q:"A team adopts a checklist to score AI outputs before use. Which item BEST captures \"fitness for purpose\" rather than raw accuracy?", options:["Are all numbers mathematically correct?","Is every cited fact verifiable?","Does the output meet the specific goal, format, and audience it was created for?","Are there any spelling mistakes?"], answer:2, explain:"<strong>Does the output meet the specific goal, format, and audience it was created for?</strong> defines fitness for purpose beyond mere correctness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Are all numbers mathematically correct?</b>: this checks accuracy, not whether the output fits its purpose.</span><span class='qd'><b>Is every cited fact verifiable?</b>: verifiability is an accuracy concern, distinct from fitness.</span><span class='qd'><b>Are there any spelling mistakes?</b>: spelling is a surface-level quality check, not fitness for purpose.</span>" },
{ id:"D4-072", domain:4, obj:"4.3", diff:"hard", q:"An AI drafts a policy that is accurate and well-formatted but conflicts with your organization's existing rules. The BEST evaluation conclusion is that it:", options:["Should be adopted immediately since it is well written","Is automatically correct because AI wrote it","Only needs a spelling review","Is not fit for use until reconciled with internal policy and context"], answer:3, explain:"<strong>Is not fit for use until reconciled with internal policy and context</strong> is correct, because output must align with an organization's specific rules to be usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Should be adopted immediately since it is well written</b>: good writing does not resolve a conflict with existing policy.</span><span class='qd'><b>Is automatically correct because AI wrote it</b>: AI authorship does not confer correctness or fit.</span><span class='qd'><b>Only needs a spelling review</b>: a policy conflict is a substantive issue, not a spelling one.</span>" },
{ id:"D4-073", domain:4, obj:"4.3", diff:"hard", q:"When evaluating AI output for a high-stakes decision, why is \"good enough on the surface\" a dangerous standard?", options:["Surface polish can mask factual or contextual gaps that matter for the decision","Surface polish guarantees the facts are correct","High-stakes decisions ignore accuracy","Polished writing cannot contain errors"], answer:0, explain:"<strong>Surface polish can mask factual or contextual gaps that matter for the decision</strong> explains the danger, because appearance can hide substantive flaws.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Surface polish guarantees the facts are correct</b>: polish and correctness are independent.</span><span class='qd'><b>High-stakes decisions ignore accuracy</b>: high-stakes decisions demand more accuracy, not less.</span><span class='qd'><b>Polished writing cannot contain errors</b>: polished writing can and does contain errors.</span>" },
{ id:"D4-074", domain:4, obj:"4.3", diff:"medium", q:"An AI answer contains a mix of clearly relevant points and several off-topic tangents. The BEST way to improve fitness is to:", options:["Keep everything to appear thorough","Refine the prompt or edit the output to keep only what serves the goal","Delete the relevant points and keep the tangents","Publish it and let readers sort it out"], answer:1, explain:"<strong>Refine the prompt or edit the output to keep only what serves the goal</strong> improves fitness by focusing the content on the actual need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep everything to appear thorough</b>: padding with tangents reduces usefulness.</span><span class='qd'><b>Delete the relevant points and keep the tangents</b>: this removes value and keeps the noise.</span><span class='qd'><b>Publish it and let readers sort it out</b>: offloading the cleanup burden lowers quality for readers.</span>" },
{ id:"D4-075", domain:4, obj:"4.3", diff:"medium", q:"Which output is BEST judged unfit even though every fact in it is true?", options:["A clear answer that matches the reader's level","A concise reply that directly addresses the request","A dense expert-level answer given to a young student who cannot follow it","A well-organized summary at the right length"], answer:2, explain:"<strong>A dense expert-level answer given to a young student who cannot follow it</strong> is unfit because accurate content still fails when the audience cannot use it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A clear answer that matches the reader's level</b>: matching the reader is a sign of fitness, not a failure.</span><span class='qd'><b>A concise reply that directly addresses the request</b>: directness and concision support fitness.</span><span class='qd'><b>A well-organized summary at the right length</b>: appropriate length and structure indicate a fit output.</span>" },
{ id:"D4-076", domain:4, obj:"4.4", diff:"easy", q:"To verify a factual claim from an AI, which source is generally MOST reliable?", options:["A random social media comment","The same AI asked a second time","A meme repeating the claim","An authoritative primary source such as an official website or original document"], answer:3, explain:"<strong>An authoritative primary source such as an official website or original document</strong> provides the strongest verification because it is the origin of the fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random social media comment</b>: anonymous comments are unvetted and unreliable.</span><span class='qd'><b>The same AI asked a second time</b>: re-asking the same tool is not independent verification.</span><span class='qd'><b>A meme repeating the claim</b>: memes carry no authority and often spread misinformation.</span>" },
{ id:"D4-077", domain:4, obj:"4.4", diff:"easy", q:"Which method BEST confirms whether an AI-provided statistic is accurate?", options:["Look it up in the original report or dataset it came from","Ask a friend if it sounds right","Check whether the AI used a big number","See if it is formatted in bold"], answer:0, explain:"<strong>Look it up in the original report or dataset it came from</strong> is the best method, because tracing a statistic to its source confirms its truth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask a friend if it sounds right</b>: a friend's impression is not authoritative evidence.</span><span class='qd'><b>Check whether the AI used a big number</b>: the size of a number says nothing about accuracy.</span><span class='qd'><b>See if it is formatted in bold</b>: formatting does not verify data.</span>" },
{ id:"D4-078", domain:4, obj:"4.4", diff:"easy", q:"Why is \"cross-referencing multiple independent sources\" a good verification habit?", options:["It makes the research take longer for its own sake","Agreement among independent sources increases confidence a claim is true","One source is always enough","It guarantees the AI was correct"], answer:1, explain:"<strong>Agreement among independent sources increases confidence a claim is true</strong> because independent corroboration reduces the chance of a shared error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the research take longer for its own sake</b>: the goal is reliability, not spending extra time.</span><span class='qd'><b>One source is always enough</b>: a single source can be wrong or biased, so more is safer.</span><span class='qd'><b>It guarantees the AI was correct</b>: cross-referencing verifies the claim, not the tool, and offers no absolute guarantee.</span>" },
{ id:"D4-079", domain:4, obj:"4.4", diff:"easy", q:"An AI cites a study. The BEST way to verify it is to:", options:["Trust it because it has a title and author","Assume it is real if it sounds academic","Find and read the actual study to confirm it exists and says what is claimed","Ask the AI to describe it again"], answer:2, explain:"<strong>Find and read the actual study to confirm it exists and says what is claimed</strong> is the strongest verification for a cited study.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust it because it has a title and author</b>: titles and authors are easily fabricated.</span><span class='qd'><b>Assume it is real if it sounds academic</b>: an academic tone is exactly what fabricated citations mimic.</span><span class='qd'><b>Ask the AI to describe it again</b>: re-describing does not confirm the study is real.</span>" },
{ id:"D4-080", domain:4, obj:"4.4", diff:"easy", q:"Which of the following is a reliable way to check whether an AI answer about current events is up to date?", options:["Assume the AI always has today's information","Check the AI's response time","Look at how long the answer is","Consult a reputable, current news outlet or official source"], answer:3, explain:"<strong>Consult a reputable, current news outlet or official source</strong> confirms currency by comparing against up-to-date reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the AI always has today's information</b>: many models have knowledge cutoffs and lack today's events.</span><span class='qd'><b>Check the AI's response time</b>: speed does not indicate how current the information is.</span><span class='qd'><b>Look at how long the answer is</b>: length is unrelated to timeliness.</span>" },
{ id:"D4-081", domain:4, obj:"4.4", diff:"easy", q:"When an AI gives you a link as a source, the FIRST thing you should do is:", options:["Open the link and confirm it exists and supports the claim","Assume it is valid because it is clickable","Share it immediately with others","Bookmark it without reading it"], answer:0, explain:"<strong>Open the link and confirm it exists and supports the claim</strong> is the correct first step, because AI links can be fabricated or unrelated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is valid because it is clickable</b>: a clickable link may lead nowhere or to unrelated content.</span><span class='qd'><b>Share it immediately with others</b>: sharing before checking can spread misinformation.</span><span class='qd'><b>Bookmark it without reading it</b>: saving it does not verify that it supports the claim.</span>" },
{ id:"D4-082", domain:4, obj:"4.4", diff:"medium", q:"An AI and a Wikipedia article agree on a fact, but both may draw from the same origin. What is the STRONGER verification step?", options:["Accept it because two places agree","Trace the fact to an independent primary source","Ask the AI to confirm a third time","Assume Wikipedia is always primary"], answer:1, explain:"<strong>Trace the fact to an independent primary source</strong> is stronger because agreement between sources sharing an origin does not rule out a common error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept it because two places agree</b>: shared-origin agreement can propagate the same mistake.</span><span class='qd'><b>Ask the AI to confirm a third time</b>: repeating the AI adds no independent evidence.</span><span class='qd'><b>Assume Wikipedia is always primary</b>: Wikipedia is a secondary source that summarizes others.</span>" },
{ id:"D4-083", domain:4, obj:"4.4", diff:"medium", q:"You want to verify an AI's claim about a law in your country. Which source is MOST authoritative?", options:["A viral video about the law","A comment thread discussing it","The official government or legislative website","The AI's own restated summary"], answer:2, explain:"<strong>The official government or legislative website</strong> is the most authoritative because it publishes the actual legal text.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A viral video about the law</b>: viral content can be inaccurate or sensationalized.</span><span class='qd'><b>A comment thread discussing it</b>: informal discussion is not authoritative.</span><span class='qd'><b>The AI's own restated summary</b>: restating the AI does not verify anything independently.</span>" },
{ id:"D4-084", domain:4, obj:"4.4", diff:"medium", q:"Which approach BEST verifies a numerical calculation an AI performed?", options:["Trust it because the steps looked organized","Assume it is right if the answer is a round number","Ask the AI whether it is sure","Redo the calculation yourself or with a calculator"], answer:3, explain:"<strong>Redo the calculation yourself or with a calculator</strong> is best, because independently recomputing catches arithmetic errors the model may make.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust it because the steps looked organized</b>: neat steps can still contain a wrong result.</span><span class='qd'><b>Assume it is right if the answer is a round number</b>: a round number is not evidence of correctness.</span><span class='qd'><b>Ask the AI whether it is sure</b>: the model's self-assurance does not confirm the math.</span>" },
{ id:"D4-085", domain:4, obj:"4.4", diff:"medium", q:"An AI claims a company reported specific quarterly revenue. Where should you verify it?", options:["The company's official financial filing or investor page","A social media rumor","The AI restating the figure","A general opinion blog"], answer:0, explain:"<strong>The company's official financial filing or investor page</strong> is the authoritative source for reported financials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A social media rumor</b>: rumors are unverified and often wrong.</span><span class='qd'><b>The AI restating the figure</b>: restating is not independent confirmation.</span><span class='qd'><b>A general opinion blog</b>: opinion blogs are not authoritative for official numbers.</span>" },
{ id:"D4-086", domain:4, obj:"4.4", diff:"medium", q:"Why is it risky to verify one AI's answer by asking a different AI the same question?", options:["It is always the most reliable method","Both models may share similar training data and repeat the same error","Two AIs can never make the same mistake","AIs automatically fact-check each other"], answer:1, explain:"<strong>Both models may share similar training data and repeat the same error</strong> is the risk, because AI-to-AI checking is not truly independent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is always the most reliable method</b>: comparing two models is weaker than checking a primary source.</span><span class='qd'><b>Two AIs can never make the same mistake</b>: models often make overlapping mistakes.</span><span class='qd'><b>AIs automatically fact-check each other</b>: they do not automatically validate one another's facts.</span>" },
{ id:"D4-087", domain:4, obj:"4.4", diff:"medium", q:"Which is the BEST practice when an AI provides a quote attributed to a public figure?", options:["Assume it is accurate if it sounds like something they would say","Post it as fact because the AI is usually right","Find the original speech, interview, or document to confirm the quote","Trust it if it includes a year"], answer:2, explain:"<strong>Find the original speech, interview, or document to confirm the quote</strong> is the best practice, because misattributed quotes are a common AI error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is accurate if it sounds like something they would say</b>: plausibility is not proof of authenticity.</span><span class='qd'><b>Post it as fact because the AI is usually right</b>: usual reliability does not guarantee this quote is real.</span><span class='qd'><b>Trust it if it includes a year</b>: a year is easily fabricated and does not verify the quote.</span>" },
{ id:"D4-088", domain:4, obj:"4.4", diff:"hard", q:"A journalist must verify an AI-surfaced claim quickly and rigorously. Which strategy BEST balances speed and reliability?", options:["Rely solely on the AI's confidence level","Search only for pages that agree with the claim","Ask several chatbots and take the majority answer","Check the claim against one or two authoritative primary sources"], answer:3, explain:"<strong>Check the claim against one or two authoritative primary sources</strong> balances speed and rigor by going straight to trustworthy origins.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rely solely on the AI's confidence level</b>: confidence is not evidence.</span><span class='qd'><b>Search only for pages that agree with the claim</b>: seeking only agreement is confirmation bias, not verification.</span><span class='qd'><b>Ask several chatbots and take the majority answer</b>: multiple models can share the same error, so a majority is not reliable.</span>" },
{ id:"D4-089", domain:4, obj:"4.4", diff:"hard", q:"An AI says a scientific consensus exists on a topic. What is the MOST rigorous way to verify this?", options:["Consult reputable scientific bodies or peer-reviewed reviews on the subject","Count how many web pages mention it","Trust the AI because science is data-heavy","Check whether the claim is stated confidently"], answer:0, explain:"<strong>Consult reputable scientific bodies or peer-reviewed reviews on the subject</strong> is the most rigorous, because authoritative scientific sources establish consensus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Count how many web pages mention it</b>: page counts reflect popularity, not scientific validity.</span><span class='qd'><b>Trust the AI because science is data-heavy</b>: data-rich topics can still be misrepresented by a model.</span><span class='qd'><b>Check whether the claim is stated confidently</b>: confidence does not establish consensus.</span>" },
{ id:"D4-090", domain:4, obj:"4.4", diff:"hard", q:"You verify an AI claim and find the primary source actually contradicts it. The correct action is to:", options:["Keep the AI's version because it is more convenient","Reject the AI's version and rely on the verified primary source","Average the two conflicting statements","Assume the primary source is outdated without checking"], answer:1, explain:"<strong>Reject the AI's version and rely on the verified primary source</strong> is correct, because verified evidence overrides an unverified AI claim.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep the AI's version because it is more convenient</b>: convenience does not make a contradicted claim true.</span><span class='qd'><b>Average the two conflicting statements</b>: averaging a true source with a false claim does not yield truth.</span><span class='qd'><b>Assume the primary source is outdated without checking</b>: dismissing verified evidence on a hunch is unjustified.</span>" },
{ id:"D4-091", domain:4, obj:"4.4", diff:"hard", q:"For a compliance report, which verification approach provides the STRONGEST assurance of an AI-stated regulation?", options:["Paraphrasing what the AI said in your own words","Linking to a blog that mentions the regulation","Citing and quoting the official regulatory text directly","Relying on the AI's summary because it saves time"], answer:2, explain:"<strong>Citing and quoting the official regulatory text directly</strong> gives the strongest assurance because the primary legal source is authoritative and auditable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paraphrasing what the AI said in your own words</b>: paraphrasing an unverified claim does not confirm it.</span><span class='qd'><b>Linking to a blog that mentions the regulation</b>: a blog is not an authoritative regulatory source.</span><span class='qd'><b>Relying on the AI's summary because it saves time</b>: convenience does not substitute for the official text in compliance.</span>" },
{ id:"D4-092", domain:4, obj:"4.5", diff:"easy", q:"In a basic AI verification workflow, what is a sensible FIRST step after receiving an output?", options:["Immediately publish the output","Delete the conversation","Change the app's settings","Identify the specific claims that need checking"], answer:3, explain:"<strong>Identify the specific claims that need checking</strong> is a sensible first step, because you must know what to verify before verifying it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately publish the output</b>: publishing before verifying defeats the purpose of the workflow.</span><span class='qd'><b>Delete the conversation</b>: deleting the chat removes the content you need to check.</span><span class='qd'><b>Change the app's settings</b>: settings changes do not verify the output's claims.</span>" },
{ id:"D4-093", domain:4, obj:"4.5", diff:"easy", q:"Which step logically comes LAST in a verification workflow?", options:["Decide whether to use, edit, or reject the output based on findings","Read the output for the first time","Identify which facts to check","Locate authoritative sources"], answer:0, explain:"<strong>Decide whether to use, edit, or reject the output based on findings</strong> is the final step, because the decision follows all the checking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read the output for the first time</b>: reading comes at the beginning, not the end.</span><span class='qd'><b>Identify which facts to check</b>: identifying claims is an early step, before verifying them.</span><span class='qd'><b>Locate authoritative sources</b>: finding sources happens before the final decision.</span>" },
{ id:"D4-094", domain:4, obj:"4.5", diff:"easy", q:"A good verification workflow treats AI output as:", options:["A final answer that never needs review","A draft to be checked, not a finished product to trust blindly","Something to publish before reading","Irrelevant to the task"], answer:1, explain:"<strong>A draft to be checked, not a finished product to trust blindly</strong> reflects the core mindset of verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A final answer that never needs review</b>: treating output as final skips verification entirely.</span><span class='qd'><b>Something to publish before reading</b>: publishing unread output is reckless.</span><span class='qd'><b>Irrelevant to the task</b>: the output is central to the task, just not to be trusted uncritically.</span>" },
{ id:"D4-095", domain:4, obj:"4.5", diff:"medium", q:"Put these workflow steps in the BEST order: (1) verify claims against sources, (2) identify claims to check, (3) read the output, (4) decide to use or reject.", options:["1, 2, 3, 4","4, 3, 2, 1","3, 2, 1, 4","2, 4, 1, 3"], answer:2, explain:"<strong>3, 2, 1, 4</strong> is the logical order: read the output, identify the claims, verify them, then decide.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>1, 2, 3, 4</b>: you cannot verify claims before reading the output and identifying them.</span><span class='qd'><b>4, 3, 2, 1</b>: deciding first, before any reading or checking, is backwards.</span><span class='qd'><b>2, 4, 1, 3</b>: this decides before verifying and reads last, which is illogical.</span>" },
{ id:"D4-096", domain:4, obj:"4.5", diff:"medium", q:"During verification, you find that most of an AI draft is solid but one key figure is wrong. The BEST workflow outcome is to:", options:["Reject the entire draft as useless","Use it unchanged since most of it is fine","Publish it and add a correction later","Edit the draft to correct the figure, then use it"], answer:3, explain:"<strong>Edit the draft to correct the figure, then use it</strong> is the best outcome, because a mostly-good draft can be salvaged by fixing the specific error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reject the entire draft as useless</b>: discarding solid work over one fixable error is wasteful.</span><span class='qd'><b>Use it unchanged since most of it is fine</b>: leaving a known wrong figure in place is unacceptable.</span><span class='qd'><b>Publish it and add a correction later</b>: publishing a known error first risks harm before the fix.</span>" },
{ id:"D4-097", domain:4, obj:"4.5", diff:"medium", q:"Which factor should MOST influence how much verification effort an AI output deserves?", options:["The stakes and consequences of being wrong","The color scheme of the tool","How quickly the answer appeared","The length of the prompt you typed"], answer:0, explain:"<strong>The stakes and consequences of being wrong</strong> should drive verification effort, since higher-risk uses demand more rigorous checking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color scheme of the tool</b>: appearance is irrelevant to how carefully you verify.</span><span class='qd'><b>How quickly the answer appeared</b>: response speed does not indicate needed scrutiny.</span><span class='qd'><b>The length of the prompt you typed</b>: prompt length does not determine verification needs.</span>" },
{ id:"D4-098", domain:4, obj:"4.5", diff:"hard", q:"A team builds a verification workflow for AI-assisted reports. Which design BEST ensures errors are caught before publication?", options:["An automatic publish with no human step","A required human review that checks key claims against sources before sign-off","A rule to trust the AI if it sounds confident","A step that only checks formatting"], answer:1, explain:"<strong>A required human review that checks key claims against sources before sign-off</strong> best catches errors by mandating verification before release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An automatic publish with no human step</b>: removing human review lets errors slip straight to publication.</span><span class='qd'><b>A rule to trust the AI if it sounds confident</b>: confidence is not a safeguard against mistakes.</span><span class='qd'><b>A step that only checks formatting</b>: formatting checks miss factual errors.</span>" },
{ id:"D4-099", domain:4, obj:"4.5", diff:"hard", q:"You are verifying an AI output under time pressure. Which triage approach is MOST responsible?", options:["Verify the easiest claims and skip the risky ones","Skip verification entirely to save time","Prioritize verifying the highest-impact claims first","Verify only the final sentence"], answer:2, explain:"<strong>Prioritize verifying the highest-impact claims first</strong> is most responsible under time pressure, because it protects against the most consequential errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verify the easiest claims and skip the risky ones</b>: skipping the risky claims leaves the biggest dangers unchecked.</span><span class='qd'><b>Skip verification entirely to save time</b>: skipping all checks abandons responsibility.</span><span class='qd'><b>Verify only the final sentence</b>: arbitrarily checking one sentence ignores where the real risk may lie.</span>" },
{ id:"D4-100", domain:4, obj:"4.5", diff:"hard", q:"A verification workflow concludes that an AI output cannot be confirmed against any reliable source. The MOST appropriate action is to:", options:["Publish it as confirmed anyway","Delete all other verified content too","Assume it is true because nothing disproved it","Withhold or clearly flag the unverified claim rather than presenting it as fact"], answer:3, explain:"<strong>Withhold or clearly flag the unverified claim rather than presenting it as fact</strong> is appropriate, because unconfirmed content should not be passed off as established.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it as confirmed anyway</b>: presenting unverified content as confirmed is misleading.</span><span class='qd'><b>Delete all other verified content too</b>: discarding good verified material because of one unverified claim is unwarranted.</span><span class='qd'><b>Assume it is true because nothing disproved it</b>: absence of disproof is not proof; the burden is to verify.</span>" }
);
